<template>
    <view>
        <view class="tab">
            <view class="tabContent">
                <view class="tabItem" :class="current == 0? 'active' : '' " @click.stop="changeTab(0)">
                    Card-San App
                </view>
                <view class="tabItem" :class="current == 1? 'active' : '' " @click.stop="changeTab(1)">
                    メンバーズカード
                </view>
            </view>
        </view>
        <view v-if="current == 0">
            <view class="logo">
                <image src="../../static/icons/dlogo.png" mode=""></image>
            </view>
            <view class="qrcode">
                <image src="../../static/images/qrcode.png" mode=""></image>
            </view>
            <view class="btns">
                <view class="btn">
                    <image src="../../static/icons/appStore.png" mode=""></image>
                </view>
                <view class="btn">
                    <image src="../../static/images/google.png" mode=""></image>
                </view>
            </view>
        </view>
        <view v-else>
            <view class="membership">
                <image :src="card" mode=""></image>
            </view>
            <view class="memName" v-text="name"></view>
            <view class="qrcode">
                <image :src="qrcode" mode=""></image>
            </view>
        </view>
    </view>
</template>
<script>
    import {getShopInfo} from "@/api/index.js"
    export default {
        data() {
            return {
                current:0,
                qrcode:"",
                name:"",
                card:""
            }
        },
        onLoad() {
            let that = this 
            getShopInfo().then((res) => {
                console.log("results",res.data.ship_info)
                if(res.code == 200){
                    that.qrcode = res.data.shop_info.qrcode
                    that.name = res.data.shop_info.shop_name
                    that.card = res.data.shop_info.default_card.image
                }
            })
        },
        methods: {
           changeTab(e){
               this.current = e
           } 
        }
    }
</script>

